import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Vehicles = () => {
  const [vehicles, setVehicles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        const response = await axios.get('http://localhost:5000/api/vehicles');
        setVehicles(response.data);
      } catch (err) {
        setError('Failed to load vehicles');
        console.error(err);
      } finally {
        setLoading(false);
      }
    };

    fetchVehicles();
  }, []);

  if (loading) return <div className="p-8 text-center">Loading vehicles...</div>;
  if (error) return <div className="p-8 text-center text-red-500">{error}</div>;

  return (
    <div className="p-8 max-w-6xl mx-auto">
      <h1 className="text-3xl font-bold mb-8">Available Vehicles</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {vehicles.map(vehicle => (
          <div key={vehicle._id} className="border rounded-lg p-6 shadow-md hover:shadow-lg transition">
            <h3 className="text-xl font-semibold mb-2">{vehicle.name}</h3>
            <p className="text-gray-600 mb-1"><strong>Type:</strong> {vehicle.type}</p>
            <p className="text-gray-600 mb-1"><strong>Price:</strong> ${vehicle.pricePerHour}/hr</p>
            <p className="text-gray-600 mb-4">{vehicle.description || 'No description'}</p>
            <p className={`font-bold ${vehicle.available ? 'text-green-600' : 'text-red-600'}`}>
              {vehicle.available ? '✅ Available' : '❌ Rented'}
            </p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Vehicles;

